    * Checks if a path exists from source to target using at most k heavy edges
    * given a specific threshold.
    * This is equivalent to a shortest path problem where the cost is the number of heavy edges.
    * We use a modified Dijkstra's algorithm.
    *
    * @param n The number of nodes.
    * @param edges The list of all edges.
    * @param source The starting node.
    * @param target The destination node.
    * @param k The maximum allowed heavy edges.
    * @param threshold The threshold for classifying edges.
    * @return True if a valid path exists, false otherwise.
    */
  private def canReach(n: Int, edges: Array[Array[Int]], source: Int, target: Int, k: Int, threshold: Int): Boolean = {
    if (source == target) return true

    // Adjacency list: Map<Node, List<(Neighbor, Weight, IsHeavy)>>
    val adj = Array.ofDim[List[(Int, Int, Boolean)]](n)

    for (edge in edges) {
      val u = edge(0)
      val v = edge(1)
      val w = edge(2)
      val isHeavy = w > threshold

      // Since the graph is undirected
      adj(u) = adj(u) :+ ((v, w, isHeavy))
      adj(v) = adj(v) :+ ((u, w, isHeavy))
    }

    // dist[i][j] = minimum number of heavy edges to reach node i using exactly j heavy edges.
    // Since we are looking for AT MOST k, we use k+1 as the size for the heavy edge count.
    // Initialize with infinity (k + 1 is a safe infinity here, as we only care up to k).
    val infinity = k + 1
    val dist = Array.ofDim[Array[Int]](n) { Array.ofDim[Int](k + 1) }

    for (i <- 0 until n) {
      for (j <- 0 until k + 1) {
        dist(i)(j) = infinity
      }
    }

    // Priority Queue stores (heavy_edge_count, node)
    // We prioritize fewer heavy edges.
    val pq = new PriorityQueue[Tuple2[Int, Int]] {
      override def compare(a: Tuple2[Int, Int], b: Tuple2[Int, Int]): Boolean = a._1 < b._1
    }

    // Start state: 0 heavy edges, at source node
    dist(source)(0) = 0
    pq.enqueue((0, source))

    while (!pq.isEmpty()) {
      val (d, u) = pq.dequeue() // d is the number of heavy edges used to reach u

      if (d > dist(u)(d)) continue

      for ((v, _, isHeavy) <- adj(u)) {
        val nextHeavy = if (isHeavy) d + 1 else d

        if (nextHeavy <= k) {
          // The cost to reach v with nextHeavy edges is 1 (if we consider the cost is 1 per heavy edge)
          // In this modified Dijkstra, the "distance" tracked by PQ is the number of heavy edges.
          val newDist = nextHeavy 

          if (newDist < dist(v)(nextHeavy)) {
            dist(v)(nextHeavy) = newDist
            pq.enqueue((newDist, v))
          }
        }
      }
    }

    // Check if target is reachable with at most k heavy edges
    for (j <- 0 to k) {
      if (dist(target)(j) <= k) {
        return true
      }
    }
    false
  }


