    * Main solver function. Uses binary search on the threshold.
    * 
    * @param n The number of nodes.
    * @param edges The list of edges.
    * @param source The source node.
    * @param target The target node.
    * @param k The maximum allowed heavy edges.
    * @return The minimum threshold, or -1.
    */
  def n(n: Long): Long = throw new NotImplementedError() // Placeholder for signature compliance if needed, though unused in logic.

  def edges(edges: Array[Array[Long]]): Array[Array[Int]] = {
    // Convert Long weights to Int for easier handling in the algorithm, 
    // as max weight 10^9 fits within standard 32-bit signed Int range.
    val intEdges = Array.ofDim[Array[Int]](edges.length)
    for (i <- 0 until edges.length) {
      intEdges(i) = Array(edges(i)(0).toInt, edges(i)(1).toInt, edges(i)(2).toInt)
    }
    intEdges
  }

  def source(source: Long): Int = source.toInt

  def target(target: Long): Int = target.toInt

  def k(k: Long): Int = k.toInt

  def solve(n: Int, edges: Array[Array[Int]], source: Int, target: Int, k: Int): Int {
    if (source == target) return 0

    // Collect all unique edge weights to define the search space for the threshold.
    // Potential optimal thresholds are either 0 or one of the existing edge weights.
    var weights = mutable.Set[Int]()
    weights.add(0) // Threshold 0 is always possible if source/target are connected by any path.
    for (edge in edges) {
      weights.add(edge(2))
    }

    val sortedWeights = weights.toSeq.sorted

    var low = 0
    var high = sortedWeights.size - 1
    var minThreshold = -1

    // Binary search over the sorted unique weights (potential thresholds)
    while (low <= high) {
      val midIndex = low + (high - low) / 2
      val currentThreshold = sortedWeights(midIndex)

      if (canReach(n, edges, source, target, k, currentThreshold)) {
        // Current threshold works, try for a smaller one
        minThreshold = currentThreshold
        high = midIndex - 1
      } else {
        // Current threshold is too small (or not enough connections exist), need a higher threshold
        low = midIndex + 1
      }
    }

    minThreshold
  }

  // Wrapper to match the required signature structure, handling conversion
  def run(nL: Long, edgesL: Array[Array[Long]], sourceL: Long, targetL: Long, kL: Long): Long = {
    val n = nL.toInt
    val edges = edgesL.map(_.map(_.toInt)).toArray
    val source = sourceL.toInt
    val target = targetL.toInt
    val k = kL.toInt

    val result = solve(n, edges, source, target, k)
    result.toLong
  }
}
